using Contoso.Scoring;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Scoring.Tests;

[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator;

    public ScoreCalculatorTests()
    {
        _calculator = new ScoreCalculator();
    }

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsValueInRange()
    {
        var percentage = _calculator.CalculatePercentage(7, 10);

        Assert.IsInRange(percentage, 0.0, 100.0);
        Assert.AreEqual(70.0, percentage);
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        var percentage = _calculator.CalculatePercentage(10, 10);

        Assert.AreEqual(100.0, percentage);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        var percentage = _calculator.CalculatePercentage(0, 10);

        Assert.AreEqual(0.0, percentage);
    }

    [TestMethod]
    public void CalculatePercentage_OneOutOfMany_ReturnsSmallPositive()
    {
        var percentage = _calculator.CalculatePercentage(1, 1000);

        Assert.IsGreaterThan(0.0, percentage);
        Assert.IsLessThan(1.0, percentage);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, -5));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade ---

    [TestMethod]
    [DataRow(100.0, "A", DisplayName = "100% -> A")]
    [DataRow(90.0, "A", DisplayName = "90% boundary -> A")]
    [DataRow(89.9, "B", DisplayName = "Just below 90% -> B")]
    [DataRow(80.0, "B", DisplayName = "80% boundary -> B")]
    [DataRow(79.9, "C", DisplayName = "Just below 80% -> C")]
    [DataRow(70.0, "C", DisplayName = "70% boundary -> C")]
    [DataRow(69.9, "D", DisplayName = "Just below 70% -> D")]
    [DataRow(60.0, "D", DisplayName = "60% boundary -> D")]
    [DataRow(59.9, "F", DisplayName = "Just below 60% -> F")]
    [DataRow(0.0, "F", DisplayName = "0% -> F")]
    public void GetGrade_AtBoundary_ReturnsExpectedGrade(double percentage, string expectedGrade)
    {
        var grade = _calculator.GetGrade(percentage);

        Assert.AreEqual(expectedGrade, grade);
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_HalfOfMax_Returns50()
    {
        var normalized = _calculator.NormalizeScore(50.0, 100.0);

        Assert.AreEqual(50.0, normalized);
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ReturnsValueInRange()
    {
        var normalized = _calculator.NormalizeScore(30.0, 80.0);

        Assert.IsInRange(normalized, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, normalized);
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var normalized = _calculator.NormalizeScore(150.0, 100.0);

        Assert.AreEqual(100.0, normalized);
    }

    [TestMethod]
    public void NormalizeScore_ZeroRaw_Returns0()
    {
        var normalized = _calculator.NormalizeScore(0.0, 100.0);

        Assert.AreEqual(0.0, normalized);
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1.0, 100.0));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, 0.0));
    }

    [TestMethod]
    public void NormalizeScore_NegativeMax_ThrowsArgumentOutOfRange()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50.0, -10.0));
    }
}

